import{$ as e,A as t,B as n,V as r}from"./chunks/framework.6NwDR3kH.js";var i=JSON.parse(`{"title":"杂","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/电脑/杂.md","filePath":"ccc/电脑/杂.md"}`),a={name:`ccc/电脑/杂.md`};function o(t,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[r(`<h1 id="杂" tabindex="-1">杂 <a class="header-anchor" href="#杂" aria-label="Permalink to “杂”">​</a></h1><h2 id="显卡解码支持" tabindex="-1">显卡解码支持 <a class="header-anchor" href="#显卡解码支持" aria-label="Permalink to “显卡解码支持”">​</a></h2><ul><li><a href="https://bluesky-soft.com/en/dxvac/deviceInfo/decoder/amd.html" target="_blank" rel="noreferrer">AMD GPU</a></li><li><a href="https://bluesky-soft.com/en/dxvac/deviceInfo/decoder/intel.html" target="_blank" rel="noreferrer">Intel GPU</a></li><li><a href="https://bluesky-soft.com/en/dxvac/deviceInfo/decoder/nvidia.html" target="_blank" rel="noreferrer">NVIDIA GPU</a></li></ul><h2 id="throttlestop" tabindex="-1">throttlestop <a class="header-anchor" href="#throttlestop" aria-label="Permalink to “throttlestop”">​</a></h2><p>  英特尔平台防降频，降温。</p><h2 id="amdcpu短板" tabindex="-1">AMDcpu短板 <a class="header-anchor" href="#amdcpu短板" aria-label="Permalink to “AMDcpu短板”">​</a></h2><ol><li>黑苹果拉跨，kvm虚拟机可以跑，gpu加速要显卡直通。</li><li>linux下很多包，库都是用iu编译，一般没问题，不排除小概率事件。</li><li>计算机专业，深度学习，科研专业软件等很容易碰到英特尔写的专用库。</li><li>尽量买独显直出机型，或无独显机型。</li></ol><h3 id="dlss3" tabindex="-1">DLSS3 <a class="header-anchor" href="#dlss3" aria-label="Permalink to “DLSS3”">​</a></h3><blockquote><p>dlss3由3个功能组成，光流法插帧，超分辨率，低延迟模式。dlss3版本的超分辨率模型40系以外的显卡一样可以启用，40系独占的是光流法插帧。</p><p>光流法插帧：利用NVOFA预测光流中间帧，将现有像素根据光流移动，深度学习补全空缺像素。个人认为最大的价值是应用于视频插帧。对于游戏而言，插帧不降低输入延迟，假设30帧插到60帧，还是不跟手。提升最大的场景是CPU单核瓶颈，然而往往是竞技类游戏，不可能开该功能增加输入延迟。更多的是锦上添花。目前最有意义的是微软模拟飞行。</p><p>pr的视频光流法插帧，在后一帧是现实存在并非预测的情况下，都不可避免出现 伪影，果冻效应，扭曲和模糊。</p><p>超分辨率：以较低分辨率渲染，利用深度学习超分辨率。</p><p>低延迟模式：cpu默认等gpu空了才会发送下一帧的数据，然后准备下下帧，在显卡满载的时候会大幅增加输入延迟，开启该功能后，cpu不再等待gpu。</p></blockquote><h2 id="legacy" tabindex="-1">legacy <a class="header-anchor" href="#legacy" aria-label="Permalink to “legacy”">​</a></h2><p><a href="https://chnhi.github.io/lxzdy/ccc/%E5%8F%B0%E5%BC%8F%E7%94%B5%E8%84%91/legacy/AM4%E4%B8%BB%E6%9D%BF.html" target="_blank" rel="noreferrer">AM4主板</a></p><p><a href="https://chnhi.github.io/lxzdy/ccc/%E5%8F%B0%E5%BC%8F%E7%94%B5%E8%84%91/legacy/LGA1151%E4%B8%BB%E6%9D%BF.html" target="_blank" rel="noreferrer">LGA1151主板</a></p><p><a href="https://chnhi.github.io/lxzdy/ccc/%E5%8F%B0%E5%BC%8F%E7%94%B5%E8%84%91/legacy/LGA1200%E4%B8%BB%E6%9D%BF.html" target="_blank" rel="noreferrer">LGA1200主板</a></p><p>Meteor Lake （14代），INTEL 4+TSMC N5，主打能效，Redwood Cove+Crestmont没有特别大的提升，chiplet增加延迟导致IPC反而有一点下降。</p>`,14)]])}var s=t(a,[[`render`,o]]);export{i as __pageData,s as default};